/**
 * SEO-страницы языковых пар (/perevod/[slug]) — единый источник данных по
 * образцу SERVICES из data/services.ts и INDUSTRIES из data/site.ts. Каждая
 * страница закрывает поисковые запросы вида «перевод с английского» —
 * тексты страниц не пересекаются, даже когда языки соседствуют по теме.
 *
 * В строковых полях intro / whoOrdersThis / faq[].a допускается разметка
 * внутренних ссылок в виде токена [[/путь|текст ссылки]] — LanguagePageBody
 * разворачивает её в настоящий <Link>, а для JSON-LD и метаданных токен
 * схлопывается до простого текста (см. stripLinkTokens).
 */

export interface LanguageLinguisticNote {
  title: string;
  desc: string;
  iconName: string;
}

export interface LanguageFaqItem {
  q: string;
  a: string;
}

export interface LanguagePage {
  slug: string; // сегмент маршрута под /perevod/
  name: string; // короткое имя для хлебных крошек и карточек
  heroTitle: string;
  metaTitle?: string; // SEO <title>; если пусто — берётся heroTitle
  heroSubtitle: string;
  intro: string[]; // вводные абзацы — основной SEO-текст страницы
  linguisticNotes: LanguageLinguisticNote[]; // особенности пары: ложные друзья, грамматика, стандарты
  typicalDocuments: string[]; // чипы форматов/типов документов
  whoOrdersThis: string; // один абзац с 2-3 инлайн-ссылками на отрасли
  faq: LanguageFaqItem[];
  relatedServiceSlugs: string[]; // существующие слаги /uslugi/*
  relatedIndustrySlugs: string[]; // существующие слаги /otrasli/*
}

